// modules/tasks/routes/taskVelocity.ts
import { defineRoute } from 'aether';
import { requireUser, getSession } from '/lib/auth';
import { query } from '/lib/db';
import { Result, ok, err } from '/lib/result';

export default defineRoute({
  method: 'GET',
  path: '/tasks/velocity',
  auth: true,
  description: 'Returns the team\'s task velocity over the last 30 days.',
  sideEffects: [],
  invariants: [],
});

async function getTaskVelocity(req: Request): Promise<Response> {
  try {
    const user = await requireUser(req);
    const session = await getSession(req);

    // Ensure the session is valid
    if (!session) {
      return err({ code: 'UNAUTHORIZED', message: 'Session expired' });
    }

    // Fetch task velocity data from the database
    const result = await query(`
      SELECT 
        DATE(completed_at) AS date,
        COUNT(*) AS tasks_completed,
        AVG(EXTRACT(EPOCH FROM (completed_at - created_at))) / 3600 AS avg_cycle_time,
        SUM(CASE WHEN completed_at IS NULL THEN 1 ELSE 0 END) AS wip_count
      FROM 
        tasks
      WHERE 
        team_id = $1 AND completed_at >= NOW() - INTERVAL '30 days'
      GROUP BY 
        DATE(completed_at)
      ORDER BY 
        date;
    `, [session.teamId]);

    if (result.error) {
      return err({ code: 'INTERNAL_ERROR', message: result.error.message });
    }

    return ok(result.rows);
  } catch (error) {
    return err({ code: 'INTERNAL_ERROR', message: error.message });
  }
}

export default getTaskVelocity;

